INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('symptom_guide', 'abdominal_pain', ARRAY['پیٹ درد','مروڑ','تیز پیٹ','معدہ'], 'پیٹ درد - تفریقی تشخیص', E'## پیٹ درد\n\n**اوپر دائیں:** پتے کی سوزش، پتھری، جگر\n**اوپر بائیں:** تلی، معدے کا السر، لبلبہ\n**نیچے دائیں:** اپنڈکس، رحم کا کیسٹ، ایکٹوپک حمل\n**نیچے بائیں:** رتج کی سوزش، گردے کی پتھری\n**پورا پیٹ:** آنتوں کی رکاوٹ، پیریٹونائٹس\n\n**خطرے کی علامات:** سخت پیٹ، بخار، خونی الٹی، آنتوں کی آواز غائب', 'ur', 'Clinical', 5, true),
('symptom_guide', 'headache_types', ARRAY['سر درد','آدھا سیسی','درد سر','مائگرین'], 'سر درد کی اقسام', E'## سر درد کی اقسام\n\n**تناؤ کا سر درد:** دبنے والا دونوں طرف، ہلکا-درمیانا\n- علاج: پیراسیٹامول، تناؤ سے نجات\n\n**آدھا سیسی (مائگرین):** دھڑکنے والا ایک طرف، شدید، متلی، روشنی سے تکلیف\n- علاج: ٹرپٹان + درد کش\n\n**عنقودی:** آنکھ کے گرد، بہت شدید، آنسو اور ناک بند\n- علاج: آکسیجن + سوماٹرپٹان\n\n**⚠️ خطرے کی علامات:** زندگی کا بدترین سر درد، اچانک، بخار + گردن اکڑن، شعور تبدیل', 'ur', 'Clinical', 5, true),
('symptom_guide', 'chest_pain', ARRAY['سینے میں درد','دل','ذبحہ','سینہ تنگ'], 'سینے میں درد', E'## سینے میں درد\n\n**دل:** دبنے والا بائیں کندھے تک، محنت سے، GTN سے بہتر\n**پھیپھڑے:** تیز سانس لینے سے بڑھے\n**معدہ:** جلن کھانے سے، اینٹی ایسڈ سے بہتر\n**پٹھے/ہڈیاں:** دبانے سے درد\n**PE:** اچانک سانس تکلیف + تیز دھڑکن\n\n**⚠️ ہنگامی:** دبنے والا درد > 20 منٹ، سانس تکلیف، ٹھنڈا پسینہ → فوری ایمرجنسی', 'ur', 'AHA/ESC', 5, true),
('symptom_guide', 'cough_evaluation', ARRAY['کھانسی','خشک کھانسی','بلغم','مزمن کھانسی'], 'کھانسی کا جائزہ', E'## کھانسی\n\n**شدید (< 3 ہفتے):**\n- سانس کا انفیکشن\n- نزلہ زکام\n- نمونیا\n\n**مزمن (> 8 ہفتے):**\n- دمہ\n- ایسڈ ریفلکس\n- ناک سے نالی میں ٹپکنا\n- ادویات (ACE inhibitors)\n- ٹی بی (کھانسی + بخار + وزن کم)\n\n**ٹیسٹ:** سینے کا ایکسرے، بلغم ٹیسٹ، spirometry\n\n**⚠️ خطرہ:** بلغم میں خون، وزن کم، تمباکو > 40 سال → پھیپھڑے کا کینسر خارج کریں', 'ur', 'BTS/NICE', 5, true),
('symptom_guide', 'joint_pain', ARRAY['جوڑوں کا درد','گٹھیا','سوجن','روماٹزم'], 'جوڑوں کا درد', E'## جوڑوں کا درد\n\n**ایک جوڑ شدید:**\n- گاؤٹ: پاؤں کا انگوٹھا، سرخ، گرم\n- جوڑ کا انفیکشن: بخار + سوجن → ہنگامی\n- چوٹ\n\n**کئی جوڑے:**\n- روماٹائڈ: چھوٹے متناظر، صبح اکڑن\n- آسٹیو آرتھرائٹس: بڑے، عمر/وزن سے\n- لوپس: نوجوان خواتین، تتلی ددورے\n\n**ٹیسٹ:** ESR, CRP, RF, Anti-CCP, یورک ایسڈ\n\n**فوری حوالہ:** سرخ گرم جوڑ + بخار', 'ur', 'EULAR/ACR', 5, true),
('symptom_guide', 'dizziness_vertigo', ARRAY['چکر','گھومنا','سر چکرانا','توازن'], 'چکر آنا اور دوار', E'## چکر آنا\n\n**حقیقی دوار (کمرہ گھومتا ہے):**\n- BPPV: سر موڑنے سے، سیکنڈوں میں\n- تیہ کی سوزش: دنوں تک مسلسل، متلی\n- مینیئر: حملے + کان گونجنا + سماعت کم\n\n**عام چکر:**\n- BP کم کھڑے ہونے پر\n- خون کی کمی\n- بے چینی\n- ادویات\n\n**ٹیسٹ:** بیٹھ کر/کھڑے ہو کر BP، CBC، شوگر، Dix-Hallpike\n\n**⚠️ فوری حوالہ:** اعصابی علامات، شدید سر درد، دوہری نظر → فالج خارج کریں', 'ur', 'Clinical', 5, true),
('symptom_guide', 'palpitations', ARRAY['دل کی دھڑکن','خفقان','تیز دھڑکن','دھک دھک'], 'دل کی دھڑکن تیز', E'## دل کی دھڑکن\n\n**عام وجوہات:**\n- بے چینی/گھبراہٹ\n- چائے/کافی\n- خون کی کمی\n- تھائرائڈ زیادہ\n- PVCs\n\n**سنگین وجوہات:**\n- AF (بے ترتیب)\n- SVT\n- VT\n\n**ٹیسٹ:** ECG، CBC، TSH، الیکٹرولائٹس، 24 گھنٹے Holter\n\n**⚠️ ہنگامی:** دھڑکن + بے ہوشی، سینے درد، سانس تکلیف، یا > 30 منٹ', 'ur', 'AHA/ESC', 5, true),
('symptom_guide', 'urinary_symptoms', ARRAY['پیشاب','جلن','بار بار پیشاب','پیشاب انفیکشن'], 'پیشاب کے مسائل', E'## پیشاب کے مسائل\n\n**نچلا انفیکشن (مثانہ):**\n- جلن، بار بار، فوری ضرورت\n- علاج: نائٹروفیورنٹوئن 100mg × 2 × 5 دن\n\n**اوپری انفیکشن (گردہ):**\n- بخار، کمر درد، متلی\n- علاج: سیپروفلوکساسین 500mg × 2 × 7 دن\n\n**بار بار پیشاب کے اور اسباب:**\n- ذیابیطس\n- پروسٹیٹ بڑھنا\n- مثانے کی زیادہ حرکت\n\n**⚠️ حوالہ:** پیشاب میں خون بغیر انفیکشن، بڑی پتھری، علاج ناکام', 'ur', 'NICE/EAU', 5, true),
('symptom_guide', 'skin_rash', ARRAY['ددورے','خارش','ایگزیما','جلد الرجی'], 'جلد کے ددورے', E'## جلد کے ددورے\n\n**خارش والے:**\n- ایگزیما: خشک متقشر، تہوں میں\n- چھپاکی: اُبھری ہوئی منتقل ہوتی\n- خارش: انگلیوں کے درمیان، رات کو\n- فنگس: گول حلقے\n\n**بغیر خارش:**\n- صدف: چاندی کی تہیں\n- گلابی: گالوں پر\n\n**⚠️ ہنگامی:**\n- ددورے + بخار + جوڑوں کا درد → سحایا خارج کریں\n- دبانے سے نہ مٹنے والے ددورے + بخار → سحایا', 'ur', 'BAD/Clinical', 5, true),
('symptom_guide', 'eye_redness', ARRAY['آنکھ سرخ','آشوب چشم','آنکھ درد','نظر'], 'آنکھ کی سرخی', E'## آنکھ کی سرخی\n\n**آشوب چشم:**\n- بیکٹیریل: پیپ → اینٹی بائیوٹک قطرے\n- وائرل: پانی دار → ٹھنڈی پٹی\n- الرجک: خارش + آنسو → اینٹی ہسٹامین\n\n**آئرائٹس:** درد، روشنی سے تکلیف، دھندلی نظر\n**گلوکوما:** شدید درد، متلی، ہالے\n**قرنیہ سوزش:** درد، روشنی تکلیف\n\n**⚠️ فوری آنکھوں کے ڈاکٹر:**\n- اچانک نظر کم\n- شدید درد\n- 48 گھنٹے میں بہتری نہیں\n- کیمیائی چوٹ → فوری 20 منٹ دھوئیں', 'ur', 'Clinical/AAO', 5, true),
('symptom_guide', 'ear_pain', ARRAY['کان درد','کان کا انفیکشن','سماعت','کان بہنا'], 'کان کا درد', E'## کان کا درد\n\n**درمیانی کان سوزش:**\n- بچوں میں، بخار، رونا\n- علاج: اموکسیسیلین 40mg/kg × 3 × 5 دن\n- ہلکی: 48 گھنٹے انتظار\n\n**بیرونی کان سوزش:**\n- تیراکی، خارش، بہنا\n- علاج: سیپروفلوکساسین + ڈیکسامیتھازون قطرے\n\n**اور وجوہات:**\n- میل جمنا\n- جبڑے کے جوڑ کی سوزش\n- دانتوں یا گلے سے منعکس درد\n\n**⚠️ حوالہ:** خونی بہاؤ، چہرے کا فالج، کان کے پیچھے سوجن + درد', 'ur', 'NICE/AAO', 5, true),
('symptom_guide', 'back_pain', ARRAY['کمر درد','پیٹھ درد','عرق النساء','ریڑھ'], 'کمر درد', E'## کمر درد\n\n**میکانیکی (90%):**\n- پٹھوں میں کھنچاؤ\n- ڈسک گھسنا\n- علاج: متحرک رہیں، درد کش، فزیو تھراپی\n\n**عرق النساء:**\n- ٹانگ میں گھٹنے سے نیچے تک درد\n- 6-8 ہفتے تحفظی علاج\n- بہتر نہ ہو تو MRI\n\n**⚠️ خطرے کی علامات (Cauda Equina):**\n- پیشاب/پاخانہ پر قابو کھونا\n- مقعد کے گرد سن ہونا\n- دونوں ٹانگوں میں کمزوری\n→ **فوری سرجیکل حوالہ**', 'ur', 'NICE/ACP', 5, true),
('symptom_guide', 'weight_loss', ARRAY['وزن کم','لاغر','کمزور','بغیر وجہ وزن گھٹنا'], 'بلا وجہ وزن کم ہونا', E'## بلا وجہ وزن کم ہونا\n\n**تعریف:** 6-12 ماہ میں بغیر کوشش > 5% وزن کم\n\n**وجوہات:**\n- ذیابیطس بے قابو\n- تھائرائڈ زیادہ\n- کینسر\n- ٹی بی\n- HIV\n- ڈپریشن\n- جذب نہ ہونا (سیلیاک)\n\n**ٹیسٹ:** CBC، ESR، CRP، شوگر، HbA1c، TSH، جگر/گردے، سینے ایکسرے، HIV\n\n**حوالہ:** > 10% کمی، گلٹی محسوس، تشویشناک علامات', 'ur', 'Clinical', 5, true),
('symptom_guide', 'fatigue', ARRAY['تھکاوٹ','کمزوری','سستی','بے حالی'], 'مزمن تھکاوٹ', E'## مزمن تھکاوٹ\n\n**عام وجوہات:**\n- خون کی کمی\n- تھائرائڈ کم\n- ذیابیطس\n- ڈپریشن/بے چینی\n- نیند خرابی\n- آئرن/وٹامن D/B12 کمی\n\n**سنگین وجوہات:**\n- کینسر\n- دل فیل\n- گردے/جگر فیل\n- آٹو امیون\n\n**ٹیسٹ:** CBC، فیریٹین، TSH، شوگر، HbA1c، جگر/گردے، وٹامن D، B12، ESR\n\n**حوالہ:** 3 ماہ + نارمل ٹیسٹ → مزمن تھکاوٹ سنڈروم', 'ur', 'NICE/Clinical', 5, true),
('symptom_guide', 'edema_swelling', ARRAY['سوجن','ورم','پانی جمنا','ٹانگیں سوجن'], 'سوجن اور ورم', E'## سوجن اور ورم\n\n**ایک طرف:**\n- DVT: درد + سوجن + سرخی → ہنگامی\n- انفیکشن\n- چوٹ/فریکچر\n- لمفاوی رکاوٹ\n\n**دونوں طرف:**\n- دل فیل: سانس تکلیف + سوجن\n- گردے فیل: جھاگ دار پیشاب + BP\n- جگر فیل: پیٹ پھولنا + یرقان\n- رگوں کی کمزوری\n- ادویات (املوڈیپین)\n\n**ٹیسٹ:** البومین، گردے/جگر، BNP، ایکو\n\n**⚠️ ہنگامی:** اچانک ایک طرف دردناک سوجن → DVT خارج کریں فوری', 'ur', 'Clinical', 5, true),
('symptom_guide', 'fever_evaluation', ARRAY['بخار','تیز بخار','گرمی','انفیکشن'], 'بخار کا جائزہ', E'## بخار\n\n**تعریف:** درجہ حرارت > 38°C\n\n**عام وجوہات:**\n- سانس کا انفیکشن\n- پیشاب انفیکشن\n- نمونیا\n- ملیریا\n\n**بنیادی ٹیسٹ:** CBC، پیشاب، سینے ایکسرے، بلڈ کلچر\n\n**⚠️ فوری حوالہ:**\n- بخار + گردن اکڑن (سحایا)\n- بخار + دبانے سے نہ مٹنے والے ددورے\n- > 40°C + شعور تبدیل\n- 3 ماہ سے کم عمر رضیع میں بخار\n- کم مدافعت والے میں بخار', 'ur', 'NICE/WHO', 5, true),
('symptom_guide', 'dyspnea', ARRAY['سانس تکلیف','سانس پھولنا','دم گھٹنا','سانس نہ آنا'], 'سانس کی تکلیف', E'## سانس کی تکلیف\n\n**شدید:**\n- دمہ کا حملہ\n- PE (خون کا لوتھڑا)\n- نیوموتھوریکس\n- پھیپھڑوں میں پانی\n- نمونیا\n\n**مزمن:**\n- COPD\n- دل فیل\n- پھیپھڑوں کا تلیف\n- شدید خون کی کمی\n- گھبراہٹ\n\n**جائزہ:** SpO2، سانس کی رفتار، ABG، سینے ایکسرے، ECG، BNP\n\n**⚠️ ہنگامی:** SpO2 < 92%، بول نہیں سکتا، نیلاہٹ، اضافی عضلات استعمال', 'ur', 'BTS/Clinical', 5, true),
('symptom_guide', 'nausea_vomiting', ARRAY['متلی','الٹی','قے','جی متلانا'], 'متلی اور الٹی', E'## متلی اور الٹی\n\n**معدے کے اسباب:** معدے کی سوزش، السر، رکاوٹ\n**اعصابی:** مائگرین، دماغ کا دباؤ بڑھنا\n**میٹابولک:** DKA، گردے فیل، حمل\n**ادویات:** درد کش، اینٹی بائیوٹک\n\n**علاج:**\n- میٹوکلوپرامائڈ 10mg × 3\n- اونڈانسیٹرون 4mg ضرورت پر\n- وجہ کا علاج\n\n**⚠️ ہنگامی:** خونی الٹی، شدید سر درد کے ساتھ الٹی، شدید پانی کمی، تیز پیٹ درد', 'ur', 'Clinical', 5, true),
('symptom_guide', 'constipation', ARRAY['قبض','پیٹ پھولنا','پاخانہ سخت','آنتیں سست'], 'قبض', E'## قبض\n\n**عام وجوہات:**\n- ریشے اور پانی کم\n- ورزش کم\n- ادویات (اوپیائڈ، آئرن، ڈپریشن کی دوائیں)\n- تھائرائڈ کم\n\n**مرحلہ وار علاج:**\n1. ریشہ + پانی + حرکت\n2. لیکٹولوز 15-30mL\n3. بساکوڈل یا سینا\n4. انیما اگر ضروری\n\n**⚠️ خطرہ:**\n- 50 سال سے زیادہ عمر + نئی قبض → بڑی آنت کا کینسر خارج\n- پاخانے میں خون\n- وزن کم\n- قبض + پھولنا + الٹی → رکاوٹ', 'ur', 'NICE/Clinical', 5, true),
('symptom_guide', 'sore_throat', ARRAY['گلا درد','گلے کی سوزش','لوزے','نگلنے میں تکلیف'], 'گلے کا درد', E'## گلے کا درد\n\n**وائرل (70-80%):**\n- ناک بہنا، کھانسی\n- علامتی علاج: درد کش + گرم مشروبات\n\n**بیکٹیریل (Strep A):**\n- Centor معیار: بخار، لوزوں پر پیپ، لمف نوڈز، کھانسی نہیں\n- 3-4 معیار: اینٹی بائیوٹک\n- اموکسیسیلین × 10 دن\n\n**⚠️ حوالہ:**\n- نگل نہیں سکتا یا منہ نہیں کھول سکتا\n- سانس تکلیف\n- لوزے کے گرد پھوڑا (ایک طرف سوجن)\n- بچوں میں سانس مشکل (خناق)', 'ur', 'NICE/IDSA', 5, true),
('symptom_guide', 'vaginal_bleeding', ARRAY['اندام نہانی خون','رحم سے خون','بے ترتیب ماہواری','سن یاس بعد خون'], 'غیر معمولی اندام نہانی خون', E'## غیر معمولی خون\n\n**بچے پیدا کرنے کی عمر:**\n- ایکٹوپک حمل → فوری حمل ٹیسٹ\n- اسقاط حمل\n- ہارمونل خرابی\n- رسولی\n- انفیکشن\n\n**سن یاس کے بعد:**\n- رحم کی اندرونی تہ کا کینسر خارج کریں\n- الٹراساؤنڈ + بایوپسی\n\n**⚠️ ہنگامی:**\n- بہت زیادہ خون + کم BP\n- حمل ٹیسٹ مثبت + درد + خون\n- سن یاس بعد خون → 2 ہفتے میں فوری حوالہ', 'ur', 'NICE/RCOG', 5, true),
('symptom_guide', 'jaundice', ARRAY['یرقان','پیلیا','جگر','بلیروبن'], 'یرقان (پیلیا)', E'## یرقان\n\n**خون سے پہلے:** خون ٹوٹنا → غیر مستقیم بلیروبن زیادہ\n**جگر:** ہیپاٹائٹس، سروسس، ادویات → انزائم بڑھے\n**جگر کے بعد:** پتھری، لبلبہ ٹیومر → مستقیم بلیروبن زیادہ\n\n**ٹیسٹ:** بلیروبن (مستقیم/غیر مستقیم)، ALT، AST، ALP، GGT، البومین، INR، پیٹ الٹراساؤنڈ\n\n**⚠️ فوری حوالہ:**\n- یرقان + بخار + درد (صفراوی نالی سوزش)\n- بغیر درد یرقان + وزن کم (ٹیومر)\n- نوزائیدہ میں 24 گھنٹے کے اندر یرقان', 'ur', 'BSG/Clinical', 5, true);
